706	  function resolvePlugins(project: ProjectConfig, agentName?: string) {
707	    const runtime = registry.get<Runtime>("runtime", project.runtime ?? config.defaults.runtime);
708	    const agent = registry.get<Agent>("agent", agentName ?? project.agent ?? config.defaults.agent);
